# Worked focus: fp-lazy-memory — Measure memory and latency tradeoffs between eager and lazy transformation.
from collections.abc import Iterable, Iterator
from itertools import islice

def valid_prefix(records: Iterable[object], limit: int) -> Iterator[int]:
    for record in islice(records, limit):
        if isinstance(record, int):
            yield record

assert list(valid_prefix(iter([5, "bad", 8]), 3)) == [5, 8]

